arguments.file_text:
@* Vertical sidebar navigation for settings sections *@

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted text-uppercase fw-semibold" style="font-size: 0.75rem; letter-spacing: 0.05em;">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link settings-nav-link @(section.Key == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="me-2">@section.Icon</span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];
}

@using sv_4faea2f8a3f34cb39e7b2d7e828ab39b.Models

<div class="settings-section">
    <h4 class="mb-4">Profile Settings</h4>

    @if (StatusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @StatusMessage
            <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Avatar URL</label>
                <input type="url" class="form-control" @bind="AvatarUrl" />
            </div>
        </div>
        <div class="col-md-4 text-center">
            <div class="avatar-preview mb-2">
                <img src="@AvatarUrl" alt="Avatar preview" class="rounded-circle border" style="width: 120px; height: 120px; object-fit: cover;" />
            </div>
            <small class="text-muted">Avatar Preview</small>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @if (IsSaving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName { get; set; } = "";
    private string Email { get; set; } = "";
    private string Bio { get; set; } = "";
    private string AvatarUrl { get; set; } = "";
    private bool IsSaving { get; set; }
    private string? StatusMessage { get; set; }

    protected override void OnParametersSet()
    {
        if (!_initialized)
        {
            LoadFromProfile();
            _initialized = true;
        }
    }

    private bool _initialized;

    private void LoadFromProfile()
    {
        DisplayName = Profile.DisplayName;
        Email = Profile.Email;
        Bio = Profile.Bio;
        AvatarUrl = Profile.AvatarUrl;
        StatusMessage = null;
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        StatusMessage = "Profile saved successfully!";
    }

    private void Discard()
    {
        LoadFromProfile();
        StateHasChanged();
    }
}

@using sv_4faea2f8a3f34cb39e7b2d7e828ab39b.Models

