                        @(Security.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@Security.TwoFactorEnabled"
                               @onchange="e => OnToggle2FA.InvokeAsync((bool)(e.Value ?? false))" />
                    </div>
                </div>
            </div>
            @if (Security.LastPasswordChange.HasValue)
            {
                <hr />
                <small class="text-muted">
                    Last password change: @Security.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                </small>
            }
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header">
            <h6 class="mb-0">Active Sessions</h6>
        </div>
        <div class="table-responsive">
            <table class="table table-hover mb-0">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Security.Sessions)
                    {
                        var isCurrent = session == Security.Sessions.FirstOrDefault();
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => ShowRevokeDialog(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>

    <RevokeSessionDialog Visible="_revokeDialogVisible"
                         SessionId="@_revokeTarget?.Id ?? "")"
                         Device="@(_revokeTarget?.Device ?? "")"
                         Location="@(_revokeTarget?.Location ?? "")"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
</div>

@code {
    [Parameter, EditorRequired] public SecuritySettings Security { get; set; } = default!;
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool _revokeDialogVisible;
    private ActiveSession? _revokeTarget;

    private void ShowRevokeDialog(ActiveSession session)
    {
        _revokeTarget = session;
        _revokeDialogVisible = true;
    }

    private async Task ConfirmRevoke(string sessionId)
    {
        _revokeDialogVisible = false;
        _revokeTarget = null;
        await OnRevokeSession.InvokeAsync(sessionId);
    }

    private void CancelRevoke()
    {
        _revokeDialogVisible = false;
        _revokeTarget = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

