@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded { get; set; }
    private string CurrentPassword { get; set; } = "";
    private string NewPassword { get; set; } = "";
    private string ConfirmPassword { get; set; } = "";
    private bool IsSubmitting { get; set; }
    private string? StatusMessage { get; set; }
    private bool IsError { get; set; }

    private void Toggle() => IsExpanded = !IsExpanded;

    private async Task SubmitAsync()
    {
        StatusMessage = null;

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            StatusMessage = "Please fill in all password fields.";
            IsError = true;
            return;
        }

        if (NewPassword != ConfirmPassword)
        {
            StatusMessage = "New password and confirmation do not match.";
            IsError = true;
            return;
        }

        IsSubmitting = true;
        await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
        IsSubmitting = false;
        CurrentPassword = "";
        NewPassword = "";
        ConfirmPassword = "";
        StatusMessage = "Password updated successfully!";
        IsError = false;
    }
}
