            <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(SelectedTheme == theme)"
                                   @onchange="() => SelectedTheme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
                    <div class="btn-group w-100" role="group">
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <button type="button"
                                    class="btn @(SelectedFontSize == size ? "btn-primary" : "btn-outline-primary")"
                                    @onclick="() => SelectedFontSize = size">
                                @size
                            </button>
                        }
                    </div>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Language</h6>
                    <select class="form-select" @bind="SelectedLanguage">
                        @foreach (var lang in Languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" id="compactMode"
                               @bind="CompactMode" />
                        <label class="form-check-label" for="compactMode">
                            <strong>Compact Mode</strong>
                            <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                        </label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
                @if (IsSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-5">
            <div class="card sticky-top" style="top: 1rem;">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body @PreviewBgClass" style="@PreviewStyle transition: all 0.2s ease;">
                    <div class="@PreviewPaddingClass">
                        <h6 style="@PreviewFontStyle">Dashboard</h6>
                        <p class="mb-2" style="@PreviewFontStyle">
                            Welcome back! Here is your activity summary.
                        </p>
                        <div class="d-flex gap-2 mb-2">
                            <span class="badge bg-primary" style="@PreviewFontStyle">12 tasks</span>
                            <span class="badge bg-success" style="@PreviewFontStyle">3 completed</span>
                        </div>
                        <button class="btn btn-sm btn-primary" style="@PreviewFontStyle" disabled>
                            Sample Button
                        </button>
                        <hr />
                        <small style="@PreviewFontStyle">
                            Theme: @SelectedTheme · Font: @SelectedFontSize · Lang: @SelectedLanguage · Compact: @(CompactMode ? "On" : "Off")
                        </small>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Appearance { get; set; } = default!;
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string SelectedTheme { get; set; } = "Light";
    private string SelectedFontSize { get; set; } = "Medium";
    private string SelectedLanguage { get; set; } = "English";
    private bool CompactMode { get; set; }
    private bool IsSaving { get; set; }
    private string? StatusMessage { get; set; }

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (!_initialized)
        {
            SelectedTheme = Appearance.Theme;
            SelectedFontSize = Appearance.FontSize;
            SelectedLanguage = Appearance.Language;
            CompactMode = Appearance.CompactMode;
            _initialized = true;
        }
    }

    private string PreviewBgClass => SelectedTheme switch
    {
        "Dark" => "bg-dark text-light",
        _ => ""
    };

    private string PreviewStyle => SelectedTheme switch
    {
        "Dark" => "background-color: #1e1e1e; color: #e0e0e0;",
        "System" => "background-color: #f0f0f0; color: #333;",
        _ => "background-color: #ffffff; color: #212529;"
    };

    private string PreviewFontStyle => SelectedFontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 0.95rem;"
    };

    private string PreviewPaddingClass => CompactMode ? "p-1" : "p-2";

    private async Task SaveAsync()
    {
        IsSaving = true;
        var updated = new AppearanceSettings(SelectedTheme, SelectedFontSize, SelectedLanguage, CompactMode);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        StatusMessage = "Appearance settings saved!";
    }
}
