@* Vertical sidebar navigation for settings sections *@

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted text-uppercase fw-semibold" style="font-size: 0.75rem; letter-spacing: 0.05em;">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link settings-nav-link @(section.Key == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="me-2">@section.Icon</span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];
}

@using sv_4faea2f8a3f34cb39e7b2d7e828ab39b.Models

<div class="settings-section">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (StatusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @StatusMessage
            <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="emailNotif" @bind="EmailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive notifications via email</div>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="pushNotif" @bind="PushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications in your browser</div>
                </label>
            </div>

            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" id="weeklyDigest" @bind="WeeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Get a weekly summary of activity</div>
                </label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">Muted Channels</h6>
            <p class="text-muted small">Uncheck channels you want to mute.</p>
            @foreach (var channel in AllChannels)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@(!MutedChannels.Contains(channel))"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label text-capitalize" for="@($"ch-{channel}")">@channel</label>
                </div>
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
        @if (IsSaving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications { get; set; }
    private bool PushNotifications { get; set; }
    private bool WeeklyDigest { get; set; }
    private HashSet<string> MutedChannels { get; set; } = [];
    private bool IsSaving { get; set; }
    private string? StatusMessage { get; set; }

    private static readonly string[] AllChannels = ["general", "announcements", "marketing", "engineering", "support"];

    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (!_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
            _initialized = true;
        }
    }

    private void ToggleChannel(string channel, bool isActive)
    {
        if (isActive)
            MutedChannels.Remove(channel);
        else
            MutedChannels.Add(channel);
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        StatusMessage = "Notification preferences saved!";
    }
}

