@if (Visible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@Device</strong> from <strong>@Location</strong>?</p>
                    <p class="text-muted small">This will immediately sign out that device.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public string SessionId { get; set; } = "";
    [Parameter] public string Device { get; set; } = "";
    [Parameter] public string Location { get; set; } = "";
    [Parameter] public EventCallback<string> OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync(SessionId);
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@using sv_4faea2f8a3f34cb39e7b2d7e828ab39b.Models

<div class="settings-section">
    <h4 class="mb-4">Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <p class="text-muted small mb-0">Add an extra layer of security to your account.</p>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(Security.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(Security.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@Security.TwoFactorEnabled"
                               @onchange="e => OnToggle2FA.InvokeAsync((bool)(e.Value ?? false))" />
                    </div>
                </div>
            </div>
            @if (Security.LastPasswordChange.HasValue)
            {
                <hr />
                <small class="text-muted">
                    Last password change: @Security.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                </small>
            }
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header">
            <h6 class="mb-0">Active Sessions</h6>
        </div>
        <div class="table-responsive">
            <table class="table table-hover mb-0">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Security.Sessions)
                    {
                        var isCurrent = session == Security.Sessions.FirstOrDefault();
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => ShowRevokeDialog(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>

    <RevokeSessionDialog Visible="_revokeDialogVisible"
                         SessionId="@_revokeTarget?.Id ?? "")"
                         Device="@(_revokeTarget?.Device ?? "")"
                         Location="@(_revokeTarget?.Location ?? "")"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
</div>

@code {
    [Parameter, EditorRequired] public SecuritySettings Security { get; set; } = default!;
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private bool _revokeDialogVisible;
    private ActiveSession? _revokeTarget;

    private void ShowRevokeDialog(ActiveSession session)
    {
        _revokeTarget = session;
        _revokeDialogVisible = true;
    }

    private async Task ConfirmRevoke(string sessionId)
    {
        _revokeDialogVisible = false;
        _revokeTarget = null;
        await OnRevokeSession.InvokeAsync(sessionId);
    }

    private void CancelRevoke()
    {
        _revokeDialogVisible = false;
        _revokeTarget = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_4faea2f8a3f34cb39e7b2d7e828ab39b.Models

<div class="settings-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (StatusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @StatusMessage
            <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(SelectedTheme == theme)"
                                   @onchange="() => SelectedTheme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
                    <div class="btn-group w-100" role="group">
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <button type="button"
                                    class="btn @(SelectedFontSize == size ? "btn-primary" : "btn-outline-primary")"
                                    @onclick="() => SelectedFontSize = size">
                                @size
                            </button>
                        }
                    </div>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Language</h6>
                    <select class="form-select" @bind="SelectedLanguage">
                        @foreach (var lang in Languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" id="compactMode"
                               @bind="CompactMode" />
                        <label class="form-check-label" for="compactMode">
                            <strong>Compact Mode</strong>
                            <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                        </label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
                @if (IsSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-5">
            <div class="card sticky-top" style="top: 1rem;">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body @PreviewBgClass" style="@PreviewStyle transition: all 0.2s ease;">
                    <div class="@PreviewPaddingClass">
                        <h6 style="@PreviewFontStyle">Dashboard</h6>
                        <p class="mb-2" style="@PreviewFontStyle">
                            Welcome back! Here is your activity summary.
                        </p>
                        <div class="d-flex gap-2 mb-2">
                            <span class="badge bg-primary" style="@PreviewFontStyle">12 tasks</span>
                            <span class="badge bg-success" style="@PreviewFontStyle">3 completed</span>
                        </div>
                        <button class="btn btn-sm btn-primary" style="@PreviewFontStyle" disabled>
                            Sample Button
                        </button>
                        <hr />
                        <small style="@PreviewFontStyle">
                            Theme: @SelectedTheme · Font: @SelectedFontSize · Lang: @SelectedLanguage · Compact: @(CompactMode ? "On" : "Off")
                        </small>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Appearance { get; set; } = default!;
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string SelectedTheme { get; set; } = "Light";
    private string SelectedFontSize { get; set; } = "Medium";
    private string SelectedLanguage { get; set; } = "English";
    private bool CompactMode { get; set; }
    private bool IsSaving { get; set; }
    private string? StatusMessage { get; set; }

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (!_initialized)
        {
            SelectedTheme = Appearance.Theme;
            SelectedFontSize = Appearance.FontSize;
            SelectedLanguage = Appearance.Language;
            CompactMode = Appearance.CompactMode;
            _initialized = true;
        }
    }

    private string PreviewBgClass => SelectedTheme switch
    {
        "Dark" => "bg-dark text-light",
        _ => ""
    };

    private string PreviewStyle => SelectedTheme switch
    {
        "Dark" => "background-color: #1e1e1e; color: #e0e0e0;",
        "System" => "background-color: #f0f0f0; color: #333;",
        _ => "background-color: #ffffff; color: #212529;"
    };

    private string PreviewFontStyle => SelectedFontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 0.95rem;"
    };

    private string PreviewPaddingClass => CompactMode ? "p-1" : "p-2";

    private async Task SaveAsync()
    {
        IsSaving = true;
        var updated = new AppearanceSettings(SelectedTheme, SelectedFontSize, SelectedLanguage, CompactMode);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        StatusMessage = "Appearance settings saved!";
    }
}

