<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="s => { _activeSection = s; }" />

    <div class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "profile":
                    <ProfileSection Profile="_profile!" OnSave="SaveProfileAsync" />
                    break;
                case "notifications":
                    <NotificationsSection Prefs="_notifPrefs!" OnSave="SaveNotificationsAsync" />
                    break;
                case "security":
                    <SecuritySection Security="_security!"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnToggle2FA="Toggle2FAAsync"
                                     OnRevokeSession="RevokeSessionAsync" />
                    break;
                case "appearance":
                    <AppearanceSection Appearance="_appearance!" OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
