.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    gap: 0;
}

/* Sidebar */
::deep .settings-sidebar {
    width: 220px;
    min-width: 220px;
    background-color: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding-top: 1rem;
}

::deep .settings-nav-link {
    display: flex;
    align-items: center;
    width: 100%;
    border: none;
    background: none;
    padding: 0.65rem 1.25rem;
    color: #495057;
    font-size: 0.925rem;
    text-align: left;
    transition: background-color 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

::deep .settings-nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

::deep .settings-nav-link.active {
    background-color: #e7f1ff;
    color: #0d6efd;
    font-weight: 600;
    border-left-color: #0d6efd;
}

/* Content area */
.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    max-width: 960px;
}

::deep .settings-section h4 {
    font-weight: 600;
    border-bottom: 1px solid #dee2e6;
    padding-bottom: 0.75rem;
}

